1	/**
2	 * Build canonical dist/esm output for the core package (including tests).
3	 *
4	 * Prereqs: pnpm install; run gen-version + build-dom-scripts first (turbo handles).
5	 * Args: none.
6	 * Env: none.
7	 * Example: pnpm run build:esm
8	 */
9	import fs from "node:fs";
10	import { spawnSync } from "node:child_process";
11	import { getRepoRootDir } from "../lib/v3/runtimePaths.js";
12	
13	const repoRoot = getRepoRootDir();
14	
15	const runNodeScript = (scriptPath: string, args: string[]) => {
16	  const result = spawnSync(process.execPath, [scriptPath, ...args], {
17	    stdio: "inherit",
18	    cwd: repoRoot,
19	  });
20	  if (result.error) {
21	    console.error(`Failed to run node ${scriptPath} ${args.join(" ")}`);
22	    console.error(result.error);
23	    process.exit(1);
24	  }
25	  if (result.status !== 0) {
26	    process.exit(result.status ?? 1);
27	  }
28	};
29	
30	fs.rmSync(`${repoRoot}/packages/core/dist/esm`, {
31	  recursive: true,
32	  force: true,
33	});
34	
35	// Core ESM emit includes generated lib/version.ts from gen-version (run in core build).
36	runNodeScript(`${repoRoot}/node_modules/typescript/bin/tsc`, [
37	  "-p",
38	  "packages/core/tsconfig.json",
39	  "--declaration",
40	]);
41	
42	fs.mkdirSync(`${repoRoot}/packages/core/dist/esm`, { recursive: true });
43	fs.writeFileSync(
44	  `${repoRoot}/packages/core/dist/esm/package.json`,
45	  '{\n  "type": "module"\n}\n',
46	);
47	fs.writeFileSync(
48	  `${repoRoot}/packages/core/dist/esm/index.js`,
49	  `export * from "./lib/v3/index.js";
50	export { default } from "./lib/v3/index.js";
51	`,
52	);
53	fs.writeFileSync(
54	  `${repoRoot}/packages/core/dist/esm/index.d.ts`,
55	  `export * from "./lib/v3/index.js";
56	export { default } from "./lib/v3/index.js";
57	`,
